<template>
  <div class="packaging-page">
    <!-- 页面标题 -->
    <div class="page-header">
      <h2 class="page-title">包装管理</h2>
      <el-button type="primary" :icon="Plus" @click="handleCreate">
        新建包装任务
      </el-button>
    </div>

    <!-- AI 满箱识别区域 -->
    <el-card class="ai-recognition-card" shadow="hover">
      <template #header>
        <div class="card-header">
          <div class="header-left">
            <el-icon class="ai-icon"><VideoCamera /></el-icon>
            <span>AI 满箱识别</span>
            <el-tag v-if="isRecognizing" type="success" effect="dark" class="status-tag">
              <el-icon class="is-loading"><Loading /></el-icon>
              识别中
            </el-tag>
            <el-tag v-else type="info" class="status-tag">待机中</el-tag>
          </div>
          <el-button type="primary" size="small" @click="toggleRecognition">
            {{ isRecognizing ? '停止识别' : '开始识别' }}
          </el-button>
        </div>
      </template>

      <div class="ai-content">
        <!-- 摄像头画面 -->
        <div class="camera-section">
          <div class="camera-placeholder">
            <el-icon v-if="!isRecognizing" class="camera-icon"><VideoCamera /></el-icon>
            <div v-if="isRecognizing" class="camera-active">
              <div class="scan-line"></div>
              <div class="camera-overlay">
                <div class="detection-box" :style="detectionBoxStyle">
                  <span class="confidence">{{ recognitionResult.confidence }}%</span>
                </div>
              </div>
            </div>
            <span class="camera-text">{{ isRecognizing ? '摄像头运行中' : '摄像头待机' }}</span>
          </div>
        </div>

        <!-- 识别结果 -->
        <div class="recognition-result">
          <h4>识别结果</h4>
          <el-descriptions :column="1" border>
            <el-descriptions-item label="识别状态">
              <el-tag :type="recognitionResult.isFull ? 'success' : 'warning'">
                {{ recognitionResult.isFull ? '已满箱' : '未满箱' }}
              </el-tag>
            </el-descriptions-item>
            <el-descriptions-item label="置信度">{{ recognitionResult.confidence }}%</el-descriptions-item>
            <el-descriptions-item label="检测时间">{{ recognitionResult.time }}</el-descriptions-item>
            <el-descriptions-item label="箱码">
              <el-input
                v-model="scannedBoxCode"
                placeholder="请扫描或输入箱码"
                clearable
                class="box-code-input"
              >
                <template #append>
                  <el-button :icon="FullScreen" @click="handleScan">扫描</el-button>
                </template>
              </el-input>
            </el-descriptions-item>
          </el-descriptions>

          <div class="action-buttons">
            <el-button type="success" :icon="Check" @click="handleConfirmBox" :disabled="!scannedBoxCode">
              确认装箱
            </el-button>
            <el-button :icon="Printer" type="primary" @click="handlePrintBarcode" :disabled="!scannedBoxCode">
              打印条码
            </el-button>
          </div>
        </div>
      </div>
    </el-card>

    <!-- 任务列表 -->
    <el-card class="task-list-card" shadow="hover">
      <template #header>
        <div class="card-header">
          <span>包装任务列表</span>
          <div class="header-actions">
            <el-input
              v-model="searchKeyword"
              placeholder="搜索任务号/工单号"
              clearable
              class="search-input"
            >
              <template #prefix>
                <el-icon><Search /></el-icon>
              </template>
            </el-input>
            <el-button :icon="Refresh" @click="loadTaskList">刷新</el-button>
          </div>
        </div>
      </template>

      <el-table
        :data="filteredTaskList"
        stripe
        border
        v-loading="loading"
        class="task-table"
      >
        <el-table-column type="index" label="序号" width="60" align="center" />
        <el-table-column prop="taskNo" label="任务号" width="140" show-overflow-tooltip />
        <el-table-column prop="workOrderNo" label="工单号" width="140" show-overflow-tooltip />
        <el-table-column prop="batchNo" label="批次号" width="140" show-overflow-tooltip />
        <el-table-column prop="productName" label="产品" min-width="150" show-overflow-tooltip />
        <el-table-column prop="planQty" label="计划数量" width="100" align="right" />
        <el-table-column prop="actualQty" label="实际数量" width="100" align="right" />
        <el-table-column prop="boxCount" label="箱数" width="80" align="right" />
        <el-table-column prop="status" label="状态" width="100" align="center">
          <template #default="{ row }">
            <el-tag :type="getStatusType(row.status)">
              {{ getStatusText(row.status) }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="200" fixed="right" align="center">
          <template #default="{ row }">
            <el-button link type="primary" :icon="View" @click="handleView(row)">查看</el-button>
            <el-button link type="primary" :icon="Edit" @click="handleEdit(row)">编辑</el-button>
            <el-button link type="danger" :icon="Delete" @click="handleDelete(row)">删除</el-button>
          </template>
        </el-table-column>
      </el-table>

      <div class="pagination-wrapper">
        <el-pagination
          v-model:current-page="pagination.page"
          v-model:page-size="pagination.pageSize"
          :page-sizes="[10, 20, 50, 100]"
          :total="pagination.total"
          layout="total, sizes, prev, pager, next, jumper"
          @size-change="handleSizeChange"
          @current-change="handleCurrentChange"
        />
      </div>
    </el-card>

    <!-- 新建/编辑对话框 -->
    <el-dialog
      v-model="dialogVisible"
      :title="dialogType === 'create' ? '新建包装任务' : '编辑包装任务'"
      width="600px"
      destroy-on-close
    >
      <el-form
        ref="formRef"
        :model="formData"
        :rules="formRules"
        label-width="100px"
        class="packaging-form"
      >
        <el-form-item label="任务号" prop="taskNo">
          <el-input v-model="formData.taskNo" placeholder="请输入任务号" clearable />
        </el-form-item>
        <el-form-item label="工单号" prop="workOrderNo">
          <el-input v-model="formData.workOrderNo" placeholder="请输入工单号" clearable />
        </el-form-item>
        <el-form-item label="批次号" prop="batchNo">
          <el-input v-model="formData.batchNo" placeholder="请输入批次号" clearable />
        </el-form-item>
        <el-form-item label="产品" prop="productName">
          <el-select v-model="formData.productName" placeholder="请选择产品" clearable style="width: 100%">
            <el-option
              v-for="item in productOptions"
              :key="item.value"
              :label="item.label"
              :value="item.value"
            />
          </el-select>
        </el-form-item>
        <el-form-item label="计划数量" prop="planQty">
          <el-input-number v-model="formData.planQty" :min="1" :max="100000" style="width: 100%" />
        </el-form-item>
        <el-form-item label="备注" prop="remark">
          <el-input
            v-model="formData.remark"
            type="textarea"
            :rows="3"
            placeholder="请输入备注信息"
          />
        </el-form-item>
      </el-form>
      <template #footer>
        <el-button @click="dialogVisible = false">取消</el-button>
        <el-button type="primary" @click="handleSubmit" :loading="submitLoading">确定</el-button>
      </template>
    </el-dialog>

    <!-- 查看详情对话框 -->
    <el-dialog
      v-model="detailDialogVisible"
      title="任务详情"
      width="700px"
      destroy-on-close
    >
      <el-descriptions :column="2" border v-if="currentTask">
        <el-descriptions-item label="任务号" :span="1">{{ currentTask.taskNo }}</el-descriptions-item>
        <el-descriptions-item label="工单号" :span="1">{{ currentTask.workOrderNo }}</el-descriptions-item>
        <el-descriptions-item label="批次号" :span="1">{{ currentTask.batchNo }}</el-descriptions-item>
        <el-descriptions-item label="产品" :span="1">{{ currentTask.productName }}</el-descriptions-item>
        <el-descriptions-item label="计划数量" :span="1">{{ currentTask.planQty }}</el-descriptions-item>
        <el-descriptions-item label="实际数量" :span="1">{{ currentTask.actualQty }}</el-descriptions-item>
        <el-descriptions-item label="箱数" :span="1">{{ currentTask.boxCount }}</el-descriptions-item>
        <el-descriptions-item label="状态" :span="1">
          <el-tag :type="getStatusType(currentTask.status)">
            {{ getStatusText(currentTask.status) }}
          </el-tag>
        </el-descriptions-item>
        <el-descriptions-item label="创建时间" :span="1">{{ currentTask.createTime }}</el-descriptions-item>
        <el-descriptions-item label="更新时间" :span="1">{{ currentTask.updateTime }}</el-descriptions-item>
        <el-descriptions-item label="备注" :span="2">{{ currentTask.remark || '-' }}</el-descriptions-item>
      </el-descriptions>
    </el-dialog>
  </div>
</template>

<script setup lang="ts">
import { ref, reactive, computed, onMounted, onUnmounted } from 'vue'
import {
  Plus,
  VideoCamera,
  Loading,
  FullScreen,
  Check,
  Printer,
  Search,
  Refresh,
  View,
  Edit,
  Delete
} from '@element-plus/icons-vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import type { FormInstance, FormRules } from 'element-plus'

// 任务状态枚举
type TaskStatus = 'pending' | 'processing' | 'completed' | 'cancelled'

// 任务类型定义
interface PackagingTask {
  id: string
  taskNo: string
  workOrderNo: string
  batchNo: string
  productName: string
  planQty: number
  actualQty: number
  boxCount: number
  status: TaskStatus
  createTime: string
  updateTime: string
  remark?: string
}

// 识别结果类型
interface RecognitionResult {
  isFull: boolean
  confidence: number
  time: string
}

// 模拟任务数据
const mockTaskList: PackagingTask[] = [
  {
    id: '1',
    taskNo: 'PKG20240605001',
    workOrderNo: 'WO20240605001',
    batchNo: 'BT20240605001',
    productName: '产品A-型号X1',
    planQty: 1000,
    actualQty: 850,
    boxCount: 17,
    status: 'processing',
    createTime: '2024-06-05 08:30:00',
    updateTime: '2024-06-05 10:15:00',
    remark: '正常生产'
  },
  {
    id: '2',
    taskNo: 'PKG20240605002',
    workOrderNo: 'WO20240605002',
    batchNo: 'BT20240605002',
    productName: '产品B-型号Y2',
    planQty: 2000,
    actualQty: 2000,
    boxCount: 40,
    status: 'completed',
    createTime: '2024-06-05 09:00:00',
    updateTime: '2024-06-05 14:30:00',
    remark: '已完成'
  },
  {
    id: '3',
    taskNo: 'PKG20240605003',
    workOrderNo: 'WO20240605003',
    batchNo: 'BT20240605003',
    productName: '产品C-型号Z3',
    planQty: 1500,
    actualQty: 0,
    boxCount: 0,
    status: 'pending',
    createTime: '2024-06-05 10:00:00',
    updateTime: '2024-06-05 10:00:00',
    remark: '待开始'
  },
  {
    id: '4',
    taskNo: 'PKG20240604001',
    workOrderNo: 'WO20240604001',
    batchNo: 'BT20240604001',
    productName: '产品A-型号X1',
    planQty: 800,
    actualQty: 800,
    boxCount: 16,
    status: 'completed',
    createTime: '2024-06-04 08:00:00',
    updateTime: '2024-06-04 16:00:00',
    remark: ''
  },
  {
    id: '5',
    taskNo: 'PKG20240604002',
    workOrderNo: 'WO20240604002',
    batchNo: 'BT20240604002',
    productName: '产品D-型号W4',
    planQty: 1200,
    actualQty: 300,
    boxCount: 6,
    status: 'processing',
    createTime: '2024-06-04 14:00:00',
    updateTime: '2024-06-05 09:30:00',
    remark: '生产中'
  }
]

// 产品选项
const productOptions = [
  { label: '产品A-型号X1', value: '产品A-型号X1' },
  { label: '产品B-型号Y2', value: '产品B-型号Y2' },
  { label: '产品C-型号Z3', value: '产品C-型号Z3' },
  { label: '产品D-型号W4', value: '产品D-型号W4' },
  { label: '产品E-型号V5', value: '产品E-型号V5' }
]

// 状态
const loading = ref(false)
const taskList = ref<PackagingTask[]>([])
const searchKeyword = ref('')
const dialogVisible = ref(false)
const detailDialogVisible = ref(false)
const dialogType = ref<'create' | 'edit'>('create')
const currentTask = ref<PackagingTask | null>(null)
const submitLoading = ref(false)
const formRef = ref<FormInstance>()

// AI 识别状态
const isRecognizing = ref(false)
const scannedBoxCode = ref('')
const recognitionResult = reactive<RecognitionResult>({
  isFull: false,
  confidence: 0,
  time: '-'
})

// 检测框样式（模拟）
const detectionBoxStyle = computed(() => {
  if (!isRecognizing.value) return {}
  return {
    top: '30%',
    left: '25%',
    width: '50%',
    height: '40%'
  }
})

// 分页
const pagination = reactive({
  page: 1,
  pageSize: 10,
  total: 0
})

// 表单数据
const formData = reactive<Partial<PackagingTask>>({
  taskNo: '',
  workOrderNo: '',
  batchNo: '',
  productName: '',
  planQty: 100,
  actualQty: 0,
  boxCount: 0,
  status: 'pending',
  remark: ''
})

// 表单验证规则
const formRules: FormRules = {
  taskNo: [{ required: true, message: '请输入任务号', trigger: 'blur' }],
  workOrderNo: [{ required: true, message: '请输入工单号', trigger: 'blur' }],
  batchNo: [{ required: true, message: '请输入批次号', trigger: 'blur' }],
  productName: [{ required: true, message: '请选择产品', trigger: 'change' }],
  planQty: [{ required: true, message: '请输入计划数量', trigger: 'blur' }]
}

// 筛选后的任务列表
const filteredTaskList = computed(() => {
  let list = taskList.value
  if (searchKeyword.value) {
    const keyword = searchKeyword.value.toLowerCase()
    list = list.filter(
      item =>
        item.taskNo.toLowerCase().includes(keyword) ||
        item.workOrderNo.toLowerCase().includes(keyword)
    )
  }
  return list
})

// 获取状态类型
const getStatusType = (status: TaskStatus): string => {
  const typeMap: Record<TaskStatus, string> = {
    pending: 'info',
    processing: 'warning',
    completed: 'success',
    cancelled: 'danger'
  }
  return typeMap[status] || 'info'
}

// 获取状态文本
const getStatusText = (status: TaskStatus): string => {
  const textMap: Record<TaskStatus, string> = {
    pending: '待开始',
    processing: '进行中',
    completed: '已完成',
    cancelled: '已取消'
  }
  return textMap[status] || status
}

// 加载任务列表
const loadTaskList = () => {
  loading.value = true
  setTimeout(() => {
    taskList.value = mockTaskList
    pagination.total = mockTaskList.length
    loading.value = false
  }, 500)
}

// 新建任务
const handleCreate = () => {
  dialogType.value = 'create'
  resetForm()
  dialogVisible.value = true
}

// 编辑任务
const handleEdit = (row: PackagingTask) => {
  dialogType.value = 'edit'
  currentTask.value = row
  Object.assign(formData, row)
  dialogVisible.value = true
}

// 查看任务
const handleView = (row: PackagingTask) => {
  currentTask.value = row
  detailDialogVisible.value = true
}

// 删除任务
const handleDelete = (row: PackagingTask) => {
  ElMessageBox.confirm(`确定要删除任务 ${row.taskNo} 吗？`, '提示', {
    confirmButtonText: '确定',
    cancelButtonText: '取消',
    type: 'warning'
  }).then(() => {
    taskList.value = taskList.value.filter(item => item.id !== row.id)
    pagination.total = taskList.value.length
    ElMessage.success('删除成功')
  })
}

// 重置表单
const resetForm = () => {
  formData.taskNo = ''
  formData.workOrderNo = ''
  formData.batchNo = ''
  formData.productName = ''
  formData.planQty = 100
  formData.actualQty = 0
  formData.boxCount = 0
  formData.status = 'pending'
  formData.remark = ''
  currentTask.value = null
}

// 提交表单
const handleSubmit = async () => {
  if (!formRef.value) return
  await formRef.value.validate((valid) => {
    if (valid) {
      submitLoading.value = true
      setTimeout(() => {
        if (dialogType.value === 'create') {
          const newTask: PackagingTask = {
            id: Date.now().toString(),
            taskNo: formData.taskNo!,
            workOrderNo: formData.workOrderNo!,
            batchNo: formData.batchNo!,
            productName: formData.productName!,
            planQty: formData.planQty!,
            actualQty: 0,
            boxCount: 0,
            status: 'pending',
            createTime: new Date().toLocaleString(),
            updateTime: new Date().toLocaleString(),
            remark: formData.remark
          }
          taskList.value.unshift(newTask)
          pagination.total = taskList.value.length
          ElMessage.success('创建成功')
        } else {
          const index = taskList.value.findIndex(item => item.id === currentTask.value?.id)
          if (index > -1) {
            taskList.value[index] = {
              ...taskList.value[index],
              ...formData,
              updateTime: new Date().toLocaleString()
            } as PackagingTask
            ElMessage.success('更新成功')
          }
        }
        submitLoading.value = false
        dialogVisible.value = false
      }, 500)
    }
  })
}

// 分页处理
const handleSizeChange = (val: number) => {
  pagination.pageSize = val
}

const handleCurrentChange = (val: number) => {
  pagination.page = val
}

// AI 识别控制
let recognitionTimer: number | null = null

const toggleRecognition = () => {
  isRecognizing.value = !isRecognizing.value
  if (isRecognizing.value) {
    ElMessage.success('AI 识别已启动')
    startRecognitionSimulation()
  } else {
    ElMessage.info('AI 识别已停止')
    stopRecognitionSimulation()
  }
}

// 模拟识别过程
const startRecognitionSimulation = () => {
  recognitionTimer = window.setInterval(() => {
    recognitionResult.isFull = Math.random() > 0.3
    recognitionResult.confidence = Math.floor(Math.random() * 20) + 80
    recognitionResult.time = new Date().toLocaleTimeString()
  }, 2000)
}

const stopRecognitionSimulation = () => {
  if (recognitionTimer) {
    clearInterval(recognitionTimer)
    recognitionTimer = null
  }
  recognitionResult.isFull = false
  recognitionResult.confidence = 0
  recognitionResult.time = '-'
}

// 扫描箱码
const handleScan = () => {
  scannedBoxCode.value = 'BOX' + Date.now().toString().slice(-8)
  ElMessage.success('扫描成功')
}

// 确认装箱
const handleConfirmBox = () => {
  if (!scannedBoxCode.value) {
    ElMessage.warning('请先扫描箱码')
    return
  }
  ElMessage.success(`箱码 ${scannedBoxCode.value} 已确认`)
  scannedBoxCode.value = ''
}

// 打印条码
const handlePrintBarcode = () => {
  if (!scannedBoxCode.value) {
    ElMessage.warning('请先扫描箱码')
    return
  }
  ElMessage.success(`正在打印条码: ${scannedBoxCode.value}`)
}

// 生命周期
onMounted(() => {
  loadTaskList()
})

onUnmounted(() => {
  stopRecognitionSimulation()
})
</script>

<style scoped lang="scss">
.packaging-page {
  padding: 20px;
  background-color: #f5f7fa;
  min-height: 100vh;
}

.page-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;

  .page-title {
    margin: 0;
    font-size: 24px;
    font-weight: 600;
    color: #303133;
  }
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;

  .header-left {
    display: flex;
    align-items: center;
    gap: 10px;
    font-weight: 600;
    font-size: 16px;

    .ai-icon {
      font-size: 20px;
      color: #409eff;
    }

    .status-tag {
      margin-left: 8px;

      .is-loading {
        animation: rotating 2s linear infinite;
        margin-right: 4px;
      }
    }
  }

  .header-actions {
    display: flex;
    gap: 10px;
    align-items: center;

    .search-input {
      width: 220px;
    }
  }
}

.ai-recognition-card {
  margin-bottom: 20px;

  .ai-content {
    display: flex;
    gap: 30px;
    flex-wrap: wrap;
  }

  .camera-section {
    flex: 1;
    min-width: 300px;

    .camera-placeholder {
      position: relative;
      width: 100%;
      height: 300px;
      background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
      border-radius: 8px;
      display: flex;
      flex-direction: column;
      justify-content: center;
      align-items: center;
      overflow: hidden;

      .camera-icon {
        font-size: 64px;
        color: #409eff;
        opacity: 0.5;
      }

      .camera-text {
        margin-top: 16px;
        color: #909399;
        font-size: 14px;
      }

      .camera-active {
        position: absolute;
        inset: 0;
        display: flex;
        justify-content: center;
        align-items: center;

        .scan-line {
          position: absolute;
          width: 100%;
          height: 2px;
          background: linear-gradient(90deg, transparent, #67c23a, transparent);
          animation: scan 2s linear infinite;
        }

        .camera-overlay {
          position: absolute;
          inset: 0;

          .detection-box {
            position: absolute;
            border: 2px solid #67c23a;
            border-radius: 4px;
            background: rgba(103, 194, 58, 0.1);
            display: flex;
            justify-content: flex-end;
            align-items: flex-start;

            .confidence {
              background: #67c23a;
              color: white;
              padding: 2px 8px;
              font-size: 12px;
              border-radius: 0 0 0 4px;
            }
          }
        }
      }
    }
  }

  .recognition-result {
    flex: 0 0 320px;

    h4 {
      margin: 0 0 16px 0;
      font-size: 16px;
      color: #303133;
    }

    .box-code-input {
      width: 100%;
    }

